import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Cadastro() {
  const navigate = useNavigate();

  const [clinics, setClinics] = useState([]);
  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    region: '',
    patient_name: '',
    patient_phone: '',
    channel: '',
    service_type: '',
    description: '',
    file: null
  });

  // 🔹 carregar clínicas
  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => setClinics(res.data))
      .catch(err => console.error(err));
  }, []);

  // 🔹 selecionar clínica (AUTO PREENCHIMENTO)
  const handleClinicChange = (e) => {
    const clinic = clinics.find(c => c.id == e.target.value);

    if (!clinic) return;

    setForm({
      ...form,
      clinic_id: clinic.id,
      city: clinic.city,
      state: clinic.state,
      region: clinic.region
    });
  };

  // 🔹 envio
  const handleSubmit = async () => {
    try {
      const formData = new FormData();

      Object.keys(form).forEach(key => {
        if (form[key]) {
          formData.append(key, form[key]);
        }
      });

      await axios.post('http://localhost:3001/complaints', formData);

      alert('Reclamação salva com sucesso!');
      navigate('/home');

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>

        <h2 style={styles.title}>Cadastro de Reclamação</h2>

        {/* CLÍNICA */}
        <select style={styles.input} onChange={handleClinicChange}>
          <option>Selecione a clínica</option>
          !c.name.includes('INATIVA')
          {clinics.map(c => (
            <option key={c.id} value={c.id}>{c.name}</option>
          ))}
        </select>

        <input style={styles.input} value={form.city} placeholder="Cidade" disabled />
        <input style={styles.input} value={form.state} placeholder="Estado" disabled />
        <input style={styles.input} value={form.region} placeholder="Região" disabled />

        <input style={styles.input} placeholder="Nome do paciente"
          onChange={e => setForm({ ...form, patient_name: e.target.value })}
        />

        <input style={styles.input} placeholder="Telefone"
          onChange={e => setForm({ ...form, patient_phone: e.target.value })}
        />

        {/* CANAL */}
        <select style={styles.input} onChange={e => setForm({ ...form, channel: e.target.value })}>
          <option>Canal</option>
          <option value="whatsapp">WhatsApp</option>
          <option value="email">Email</option>
          <option value="google">Google</option>
          <option value="facebook">Facebook</option>
          <option value="instagram">Instagram</option>
          <option value="nps">NPS</option>
        </select>

        {/* SERVIÇO */}
        <select style={styles.input} onChange={e => setForm({ ...form, service_type: e.target.value })}>
          <option>Tipo de serviço</option>
          <option value="clinico">Clínico Geral</option>
          <option value="ortodontia">Ortodontia</option>
          <option value="implante">Implante</option>
          <option value="endodontia">Endodontia</option>
        </select>

        <textarea style={styles.textarea}
          placeholder="Descrição da reclamação"
          onChange={e => setForm({ ...form, description: e.target.value })}
        />

        {/* UPLOAD */}
        <input type="file"
          onChange={e => setForm({ ...form, file: e.target.files[0] })}
        />

        <div style={styles.buttons}>
          <button style={styles.back} onClick={() => navigate('/home')}>
            Voltar
          </button>

          <button style={styles.save} onClick={handleSubmit}>
            Salvar
          </button>
        </div>

      </div>
    </div>
  );
}

const styles = {
  container: {
    background: '#f5f6fa',
    height: '100vh',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center'
  },
  card: {
    background: '#fff',
    padding: 30,
    borderRadius: 10,
    width: 400,
    boxShadow: '0 5px 20px rgba(0,0,0,0.1)'
  },
  title: {
    textAlign: 'center',
    marginBottom: 20
  },
  input: {
    width: '100%',
    padding: 10,
    marginBottom: 10,
    borderRadius: 6,
    border: '1px solid #ccc'
  },
  textarea: {
    width: '100%',
    padding: 10,
    height: 80,
    marginBottom: 10,
    borderRadius: 6,
    border: '1px solid #ccc'
  },
  buttons: {
    display: 'flex',
    justifyContent: 'space-between'
  },
  back: {
    background: '#aaa',
    color: '#fff',
    border: 'none',
    padding: 10,
    borderRadius: 6
  },
  save: {
    background: '#1976d2',
    color: '#fff',
    border: 'none',
    padding: 10,
    borderRadius: 6
  }
};

export default Cadastro;
